#include <iostream>

int main() {
  int number = 42;
  int* ptr = &number;
  std::cout << "Address: " << ptr << std::endl;
  std::cout << "Value: " << *ptr << std::endl;
  return 0;
}
// Output (ünvan dəyişə bilər):
// Address: 0x7ffee4a0
// Value: 42

#include <iostream>

void updateValue(int* ptr) {
  *ptr = 100;
}

int main() {
  int value = 50;
  updateValue(&value);
  std::cout << "Updated value: " << value << std::endl;
  return 0;
}
// Output:
// Updated value: 100

#include <iostream>

int main() {
  int numbers[3] = {10, 20, 30};
  int* ptr = numbers;
  std::cout << "First element: " << *ptr << std::endl;
  std::cout << "Second element: " << *(ptr + 1) << std::endl;
  return 0;
}
// Output:
// First element: 10
// Second element: 20

#include <iostream>

int main() {
  int* ptr = new int;
  *ptr = 25;
  std::cout << "Dynamic value: " << *ptr << std::endl;
  delete ptr;
  return 0;
}
// Output:
// Dynamic value: 25

